#!/usr/bin/env bash
set -euo pipefail

# Freddy Fix It — cumulative SUPERSET installer.
# Batch: contractor lead/payout/won-bid alerts, time-based earnings + weekly
# goal, rehire-your-pro + favorites, seasonal/recurring reminders, Freddy
# Rewind share cards, and referral first-job 3% fee waiver — plus every prior
# feature. Running THIS file delivers everything; it supersedes all earlier
# apply-*.sh. DB migrations and edge-function deploys are applied live (not here).

TARGET="$HOME/Desktop/freddy-fixit"
if [ ! -d "$TARGET/.git" ]; then echo "❌ $TARGET is not a git repo"; exit 1; fi
cd "$TARGET"
echo "→ Writing files into $TARGET"

write_file() {  # write_file <destpath>  ; base64 body follows on stdin until EOF marker
  local dest="$1"
  mkdir -p "$(dirname "$dest")"
  base64 --decode > "$dest"
}

